#include <bits/stdc++.h>
using namespace std;

int n, q;
vector<vector<int>> adj;
vector<int> sz;
vector<bool> visited;

int dfs(int cur) {
    visited[cur] = true;
    int s = 1;
    for (int nxt : adj[cur]) {
        if (!visited[nxt]) s += dfs(nxt);
    }
    sz[cur] = s;
    return s;
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    cin >> n >> q;
    adj.assign(n + 1, {});
    sz.assign(n + 1, 0);
    visited.assign(n + 1, false);
    for (int i = 0; i < n - 1; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    dfs(1);
    cout << sz[q] << "\n";
    return 0;
}
